<?php use Browser\Core\Csrf; use Browser\Core\View; $signalLabel = match ($healthSignal) {1=>'Saludable',0=>'Pendiente',default=>'Riesgo'}; ?>
<div class="card"><h1><?= View::e($campaign['name']) ?></h1><p><strong>Cliente:</strong> <?= View::e($campaign['client_company_name']) ?></p><p><strong>Estado:</strong> <?= View::e($campaign['status']) ?></p><p><strong>campaign_health_signal:</strong> <?= View::e((string)$healthSignal) ?> (<?= View::e($signalLabel) ?>)</p><p><strong>Canal:</strong> <?= View::e($campaign['channel']) ?></p><p><strong>Presupuesto:</strong> <?= View::e((string)($campaign['budget'] ?? '')) ?></p><p><strong>Rango:</strong> <?= View::e((string)($campaign['start_date'] ?? '')) ?> - <?= View::e((string)($campaign['end_date'] ?? '')) ?></p><p><strong>Descripción:</strong><br><?= nl2br(View::e((string)$campaign['description'])) ?></p><p><a href="/marketing/campaigns">Listado</a><?php if ($canWrite): ?> · <a href="/marketing/campaigns/edit?id=<?= View::e((string)$campaign['id']) ?>">Editar</a><?php endif; ?></p></div>
<?php if ($canWrite): ?>
<form class="card" style="margin-top:16px;" method="post" action="/marketing/campaigns/status"><?= Csrf::field() ?><input type="hidden" name="id" value="<?= View::e((string)$campaign['id']) ?>"><label>Cambiar estado <select name="status"><?php foreach (['draft','active','paused','completed','cancelled'] as $st): ?><option value="<?= View::e($st) ?>" <?= $campaign['status']===$st?'selected':'' ?>><?= View::e($st) ?></option><?php endforeach; ?></select></label><button class="button secondary" type="submit">Actualizar estado</button></form>
<form class="card" style="margin-top:16px;" method="post" action="/marketing/campaigns/delete" onsubmit="return confirm('¿Eliminar campaña?');"><?= Csrf::field() ?><input type="hidden" name="id" value="<?= View::e((string)$campaign['id']) ?>"><button class="button" type="submit">Eliminar campaña</button></form>
<?php endif; ?>
